import os
import json
import logging
from flask import Flask, request, jsonify
from kafka import KafkaProducer
from kafka.errors import NoBrokersAvailableError, KafkaError

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Kafka configuration
# KAFKA_BOOTSTRAP_SERVERS should be an environment variable
# e.g., export KAFKA_BOOTSTRAP_SERVERS='localhost:9092,kafka1:9092'
KAFKA_BOOTSTRAP_SERVERS = os.environ.get('KAFKA_BOOTSTRAP_SERVERS', 'localhost:9092').split(',')

producer = None

def get_kafka_producer():
    """Initializes and returns a KafkaProducer instance."""
    global producer
    if producer is None:
        try:
            producer = KafkaProducer(
                bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
                value_serializer=lambda v: json.dumps(v).encode('utf-8'),
                acks='all',  # Require all in-sync replicas to acknowledge the write
                retries=5,   # Retry up to 5 times on transient errors
                linger_ms=10, # Wait for up to 10ms to batch messages
                api_version=(0, 10), # Specify API version for broader compatibility
                # security_protocol='SASL_SSL', # Uncomment for SASL_SSL authentication
                # sasl_mechanism='PLAIN',
                # sasl_plain_username='your_username',
                # sasl_plain_password='your_password'
            )
            logging.info(f"KafkaProducer initialized successfully with servers: {KAFKA_BOOTSTRAP_SERVERS}")
        except NoBrokersAvailableError:
            logging.error(f"No Kafka brokers available at {KAFKA_BOOTSTRAP_SERVERS}")
            producer = None
        except KafkaError as e:
            logging.error(f"Error initializing KafkaProducer: {e}")
            producer = None
    return producer

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message_data = request.get_json()

    if not topic_name:
        return jsonify({"error": "Topic name is required. Use ?topic=<topic_name>"}), 400

    if not message_data:
        return jsonify({"error": "Request body must contain JSON message data"}), 400

    current_producer = get_kafka_producer()
    if current_producer is None:
        return jsonify({"error": "Kafka producer is not initialized or not available."
                                 "Check KAFKA_BOOTSTRAP_SERVERS environment variable and Kafka broker status."}), 503

    try:
        # As per requirement: producer.send(topic_name, message)
        future = current_producer.send(topic_name, message_data)
        record_metadata = future.get(timeout=10) # Block until a result is returned or timeout after 10 seconds

        response_message = {
            "status": "Message published successfully",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
            "message_data": message_data
        }
        logging.info(f"Published message to topic '{topic_name}': {message_data}")
        return jsonify(response_message), 200

    except KafkaError as e:
        logging.error(f"Failed to publish message to topic '{topic_name}': {e}")
        return jsonify({"error": f"Failed to publish message: {e}"}), 500
    except Exception as e:
        logging.error(f"An unexpected error occurred: {e}")
        return jsonify({"error": f"An unexpected error occurred: {e}"}), 500

@app.route('/health', methods=['GET'])
def health_check():
    """
    A simple health check endpoint.
    Optionally, could try to connect to Kafka to verify producer health more deeply.
    """
    if get_kafka_producer() is not None:
        return jsonify({"status": "healthy", "kafka_producer_status": "initialized"}), 200
    else:
        return jsonify({"status": "unhealthy", "kafka_producer_status": "not initialized"}), 503

if __name__ == '__main__':
    # Initialize producer on startup to catch initial connection issues early
    get_kafka_producer()

    # Run the Flask app
    # In a production environment, use a production-ready WSGI server like Gunicorn
    # e.g., gunicorn -w 4 -b 0.0.0.0:5000 app:app
    app_host = os.environ.get('FLASK_RUN_HOST', '0.0.0.0')
    app_port = int(os.environ.get('FLASK_RUN_PORT', 5000))
    logging.info(f"Starting Flask app on {app_host}:{app_port}")
    app.run(host=app_host, port=app_port, debug=False) # Set debug=True for development only